import json

# Load English literature books data
english_books_data = locals()['var_functions.execute_python:14']
if isinstance(english_books_data, str) and english_books_data.endswith('.json'):
    with open(english_books_data, 'r') as f:
        english_books = json.load(f)['english_books']
else:
    english_books = english_books_data['english_books']

# Load all reviews
reviews_data = locals()['var_functions.query_db:18']
if isinstance(reviews_data, str) and reviews_data.endswith('.json'):
    with open(reviews_data, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_data

print(f"Total English literature books: {len(english_books)}")
print(f"Total reviews: {len(reviews)}")

# Group ratings by purchase_id
ratings_by_purchase = {}
for review in reviews:
    purchase_id = review['purchase_id']
    rating = float(review['rating'])
    if purchase_id not in ratings_by_purchase:
        ratings_by_purchase[purchase_id] = []
    ratings_by_purchase[purchase_id].append(rating)

# Calculate average rating for each purchase_id
avg_ratings = {}
for purchase_id, ratings in ratings_by_purchase.items():
    avg_rating = sum(ratings) / len(ratings)
    avg_ratings[purchase_id] = {
        'average': avg_rating,
        'count': len(ratings)
    }

print(f"Purchase IDs with reviews: {len(avg_ratings)}")

# Find purchase_ids with perfect 5.0 average rating
perfect_ratings = {k: v for k, v in avg_ratings.items() if abs(v['average'] - 5.0) < 0.001}
print(f"Purchase IDs with perfect 5.0 rating: {len(perfect_ratings)}")

# Show sample perfect ratings
for i, (pid, info) in enumerate(list(perfect_ratings.items())[:5]):
    print(f"  {pid}: avg={info['average']:.2f}, count={info['count']}")

print("__RESULT__:")
print(json.dumps({
    'perfect_purchase_ids': list(perfect_ratings.keys()),
    'total_perfect': len(perfect_ratings)
}))

